/**
 * n8n Function node (ES5-friendly)
 * Extracts font-family for each requested content string from Gmail HTML.
 *
 * Input:
 *   - $json.html : full Gmail HTML body (string) — escaped or real
 *
 * Output (array of items):
 *   [{ json: { 
 *        Content, 
 *        "Actual font family", 
 *        "Tag name", 
 *        "Tag snippet (escaped)", 
 *        "Anchor href" 
 *     } 
 *   }, ...]
 */

// -------------------- Utilities --------------------
function unescapeHtmlEntities(s) {
  if (!s) return "";
  return s
    .replace(/&amp;lt;/g, "&lt;")
    .replace(/&amp;gt;/g, "&gt;")
    .replace(/&amp;amp;/g, "&amp;")
    .replace(/&amp;quot;/g, "\"")
    .replace(/&amp;#39;/g, "'")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&amp;/g, "&")
    .replace(/&quot;/g, "\"")
    .replace(/&#39;/g, "'");
}

function escapeHtml(s) {
  if (!s) return "";
  return s.replace(/&/g, "&amp;")
          .replace(/</g, "&lt;")
          .replace(/>/g, "&gt;")
          .replace(/"/g, "&quot;")
          .replace(/'/g, "&#39;");
}

function innerText(htmlFrag) {
  if (!htmlFrag) return "";
  var noTags = htmlFrag.replace(/<[^>]*>/g, " ");
  return unescapeHtmlEntities(noTags)
    .replace(/\s+/g, " ")
    .trim();
}

function parseAttributes(openingTag) {
  var attrs = {};
  var attrRegex = /([a-zA-Z_:][-a-zA-Z0-9_:.]*)\s*=\s*("([^"]*)"|'([^']*)')/g;
  var m;
  while ((m = attrRegex.exec(openingTag)) !== null) {
    attrs[m[1]] = (m[3] || m[4] || "").trim();
  }
  return attrs;
}

function normalizeFontFamily(ff) {
  if (!ff) return null;
  return ff.toLowerCase()
           .replace(/["']/g, "")
           .replace(/\s*,\s*/g, ",")
           .replace(/\s+/g, " ")
           .trim();
}

function extractFontFamilyFromStyle(style) {
  if (!style || typeof style !== "string") return null;
  var low = style.toLowerCase();
  var idx = low.indexOf("font-family");
  if (idx === -1) return null;
  var s = style.slice(idx);
  var colonIdx = s.indexOf(":");
  if (colonIdx === -1) return null;
  s = s.slice(colonIdx + 1);
  var semiIdx = s.indexOf(";");
  if (semiIdx !== -1) s = s.slice(0, semiIdx);
  return normalizeFontFamily(s);
}

// -------------------- Core logic (unchanged) --------------------
// ... [functions: escRe, makeFlexibleRegex, findTextIndex, findEnclosingTag, 
// findAncestorWithFont, scanTagsForText, getTagAndFont, getFontForMultiline] ...

// -------------------- Read inputs --------------------
var htmlRaw = ($json && typeof $json.html === "string") ? $json.html : "";
var htmlReal = unescapeHtmlEntities(htmlRaw);

// -------------------- Build content list --------------------
var contentList = [];

if ($json && Array.isArray($json.searchItems) && $json.searchItems.length) {
  for (var si = 0; si < $json.searchItems.length; si++) {
    var v = $json.searchItems[si];
    if (typeof v === "string" && v.trim().length) contentList.push(v.trim());
  }
} else if ($json && typeof $json.Content === "string" && $json.Content.trim().length) {
  var parts = $json.Content.split(/\r?\n/);
  for (var p = 0; p < parts.length; p++) {
    var s = parts[p].trim();
    if (s) contentList.push(s);
  }
} else {
  // Default: generic placeholders for validation
  contentList = [
    "Sample Heading Text",
    "Sample body copy paragraph with multiple lines.\n\nWhy attend?\n\nLearn how to validate fonts in email content\nUnderstand how font-family impacts branding\nDiscover effective QA strategies\nExplore accessibility considerations\nGet answers in a live Q&A",
    "For immediate support, please contact us",
    "Let's Connect",
    "Privacy Policy",
    "You received this email because you are subscribed to updates.",
    "Company Name | Address Line | City, State ZIP",
    "Unsubscribe"
  ];
}

// -------------------- Produce outputs --------------------
var items = [];

for (var ci = 0; ci < contentList.length; ci++) {
  var content = String(contentList[ci]);

  var result;
  if (/\\n|\r?\n/.test(content)) {
    result = getFontForMultiline(htmlReal, content);
  } else {
    var variants = [content];
    if (/\s\|\s/.test(content)) variants.push(content.replace(/\s*\|\s*/g, " "));
    result = null;
    for (var vi = 0; vi < variants.length; vi++) {
      var res = getTagAndFont(htmlReal, variants[vi]);
      if (res && (res.fontFamily || res.tagStructureReal)) { result = res; break; }
    }
    if (!result) result = { tagName: null, fontFamily: "", attrs: {}, tagStructureReal: null, anchorHref: null };
  }

  var tagStructureEsc = result.tagStructureReal ? escapeHtml(result.tagStructureReal) : "Not Found";

  items.push({
    json: {
      Content: content,
      "Actual font family": result.fontFamily || "",
      "Tag name": result.tagName || null,
      "Tag snippet (escaped)": tagStructureEsc,
      "Anchor href": result.anchorHref || null
    }
  });
}

return items;

